      iconSize: [32, 40],
      iconAnchor: [16, 20]
    });
    boatMarker = L.marker([boatPosition.lat, boatPosition.lon], { icon: boatIcon, draggable: true }).addTo(map);

    // Allow dragging the boat to change position
    boatMarker.on('dragend', function(e) {
      var pos = e.target.getLatLng();
