  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  width: 36px; height: 36px;
  background: var(--bg-dark);
  border: 2px solid var(--border-color);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.65rem;
  color: var(--text-muted);
  z-index: 2;
}
.compass-direction {
  position: absolute;
  display: flex;
  flex-direction: column;
  align-items: center;
  cursor: pointer;
  transition: transform 0.2s ease;
}
.compass-direction:hover {
  transform: scale(1.08);
}
.compass-direction .dir-label {
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  margin-bottom: 0.15rem;
}
.compass-direction .dir-segment {
  width: 44px;
  height: 8px;
  border-radius: 4px;
  transition: background-color 0.3s ease;
}
.compass-direction .dir-score {
  font-size: 0.6rem;
  font-family: var(--font-mono);
  color: var(--text-muted);
  margin-top: 0.15rem;
}
/* Direction positions — radiating from center */
.compass-direction.dir-N  { top: 2px; left: 50%; transform: translateX(-50%); }
.compass-direction.dir-NE { top: 22px; right: 14px; }
.compass-direction.dir-E  { top: 50%; right: 2px; transform: translateY(-50%); }
.compass-direction.dir-SE { bottom: 22px; right: 14px; }
.compass-direction.dir-S  { bottom: 2px; left: 50%; transform: translateX(-50%); }
.compass-direction.dir-SW { bottom: 22px; left: 14px; }
.compass-direction.dir-W  { top: 50%; left: 2px; transform: translateY(-50%); }
.compass-direction.dir-NW { top: 22px; left: 14px; }

/* Color-coded segments */
.dir-segment.green  { background: var(--green); box-shadow: 0 0 8px rgba(34, 197, 94, 0.4); }
.dir-segment.yellow { background: var(--yellow); box-shadow: 0 0 8px rgba(234, 179, 8, 0.4); }
.dir-segment.red    { background: var(--red); box-shadow: 0 0 8px rgba(239, 68, 68, 0.4); }

/* Direction tooltip */
.compass-tooltip {
  position: absolute;
  bottom: -60px;
  left: 50%;
  transform: translateX(-50%);
  background: var(--bg-panel);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  padding: 0.5rem 0.75rem;
  width: 240px;
  text-align: center;
  font-size: 0.75rem;
  color: var(--text-secondary);
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.2s ease;
}
.compass-tooltip.visible {
  opacity: 1;
}

/* ===== Timeline Panel (bottom) ===== */
#timeline-panel {
  bottom: 1rem;
  left: 50%;
  transform: translateX(-50%);
  width: min(90vw, 600px);
  padding: 0.75rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}
.timeline-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.timeline-label {
  font-size: 0.8rem;
  color: var(--text-secondary);
  font-weight: 600;
}
.timeline-time {
  font-size: 0.8rem;
  font-family: var(--font-mono);
  color: var(--accent);
}

/* ===== Timeline Play/Pause Button ===== */
#timeline-play-btn {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  border: 1.5px solid var(--accent);
  background: var(--accent-dim);
  color: var(--accent);
  font-size: 0.7rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s ease, border-color 0.2s ease, transform 0.15s ease;
  flex-shrink: 0;
  line-height: 1;
  padding: 0;
}
#timeline-play-btn:hover {
  background: rgba(56, 189, 248, 0.3);
  transform: scale(1.1);
}
#timeline-play-btn:active {
  transform: scale(0.95);
}
/* Playing state — filled accent background */
#timeline-play-btn.playing {
  background: var(--accent);
  color: var(--bg-dark);
  border-color: var(--accent);
  box-shadow: 0 0 10px rgba(56, 189, 248, 0.5);
}
#timeline-play-btn.playing:hover {
  background: #5cc9f9;
  border-color: #5cc9f9;
}

/* Slider base */
.timeline-slider {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 6px;
  background: linear-gradient(90deg, var(--accent-dim) 0%, var(--accent) 100%);
  border-radius: 3px;
  outline: none;
  cursor: pointer;
}
.timeline-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  width: 18px; height: 18px;
  background: var(--accent);
  border-radius: 50%;
  border: 2px solid var(--bg-dark);
  cursor: grab;
  box-shadow: 0 0 8px rgba(56, 189, 248, 0.5);
  transition: box-shadow 0.3s ease;
}
.timeline-slider::-moz-range-thumb {
  width: 18px; height: 18px;
  background: var(--accent);
  border-radius: 50%;
  border: 2px solid var(--bg-dark);
  cursor: grab;
  box-shadow: 0 0 8px rgba(56, 189, 248, 0.5);
  transition: box-shadow 0.3s ease;
}

/* Pulsing thumb glow while timeline is playing */
@keyframes thumb-pulse {
  0%, 100% { box-shadow: 0 0 8px rgba(56, 189, 248, 0.5); }
  50% { box-shadow: 0 0 16px rgba(56, 189, 248, 0.9), 0 0 24px rgba(56, 189, 248, 0.3); }
}
.timeline-slider.playing::-webkit-slider-thumb {
  animation: thumb-pulse 1.5s ease-in-out infinite;
}
.timeline-slider.playing::-moz-range-thumb {
  animation: thumb-pulse 1.5s ease-in-out infinite;
}

.timeline-ticks {
  display: flex;
  justify-content: space-between;
  padding: 0 2px;
}
.timeline-tick {
  font-size: 0.6rem;
  color: var(--text-muted);
  font-family: var(--font-mono);
}

/* ===== Boat Marker ===== */
.boat-marker {
  transition: transform 0.5s ease;
}
.boat-marker svg {
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5));
}

/* ===== Info Bar (bottom-left) ===== */
#info-bar {
  position: absolute;
  bottom: 5.5rem;
  left: 1rem;
  z-index: 10;
  background: var(--bg-panel);
  backdrop-filter: blur(12px);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  padding: 0.5rem 0.75rem;
  display: flex;
  gap: 1rem;
  font-size: 0.75rem;
}
.info-item {
  display: flex;
  align-items: center;
  gap: 0.35rem;
}
.info-item .info-label {
  color: var(--text-muted);
}
.info-item .info-value {
  color: var(--text-primary);
  font-family: var(--font-mono);
  font-weight: 600;
}

/* ===== Layer Toggle Panel (bottom-right, above action buttons) ===== */
#layer-panel {
  bottom: 11.5rem;
  right: 1rem;
  min-width: 150px;
  padding: 0.6rem 0.75rem;
}
.layer-panel-title {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
  padding-bottom: 0.35rem;
  border-bottom: 1px solid var(--border-color);
}
.layer-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.25rem 0;
}
.layer-toggle {
  -webkit-appearance: none;
  appearance: none;
  width: 16px;
  height: 16px;
  border: 1.5px solid var(--border-color);
  border-radius: 3px;
  background: transparent;
  cursor: pointer;
  position: relative;
  flex-shrink: 0;
  transition: background 0.2s ease, border-color 0.2s ease;
}
.layer-toggle:checked {
  background: var(--accent);
  border-color: var(--accent);
}
.layer-toggle:checked::after {
  content: '\2713';
  position: absolute;
  top: -1px;
  left: 2px;
  font-size: 0.65rem;
  color: var(--bg-dark);
  font-weight: 700;
}
.layer-toggle:hover {
  border-color: var(--accent);
}
.layer-toggle:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}
.layer-row label {
  font-size: 0.8rem;
  color: var(--text-primary);
  cursor: pointer;
  user-select: none;
}

/* ===== Action Buttons Container (bottom-right) ===== */
#action-buttons {
  position: absolute;
  bottom: 5.5rem;
  right: 1rem;
  z-index: 10;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  align-items: flex-end;
}

/* ===== Shared button base for Refresh & Location ===== */
#action-buttons button {
  background: var(--bg-panel);
  backdrop-filter: blur(12px);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  padding: 0.5rem 0.75rem;
  color: var(--accent);
  font-size: 0.8rem;
  font-weight: 600;
  font-family: var(--font);
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  transition: background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
  white-space: nowrap;
}
#action-buttons button:hover {
  background: var(--bg-panel-hover);
  border-color: var(--accent);
}

/* ===== Refresh Button ===== */
#refresh-btn.loading {
  opacity: 0.6;
  pointer-events: none;
}
#refresh-btn .refresh-icon {
  transition: transform 0.5s ease;
}
#refresh-btn.loading .refresh-icon {
  animation: spin 1s linear infinite;
}

/* ===== Location Button ===== */
#location-btn .location-icon {
  font-size: 1rem;
  line-height: 1;
}
#location-btn.loading {
  opacity: 0.6;
  pointer-events: none;
}
#location-btn.loading .location-icon {
  animation: pulse 1s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.5; transform: scale(0.9); }
}

/* ===== Toast Notification ===== */
#toast-container {
  position: fixed;
  bottom: 9rem;
  right: 1rem;
  z-index: 100;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  align-items: flex-end;
  pointer-events: none;
}
.toast {
  pointer-events: auto;
  background: rgba(10, 22, 40, 0.95);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(239, 68, 68, 0.4);
  border-left: 3px solid var(--red);
  border-radius: 8px;
  padding: 0.65rem 1rem;
  color: var(--text-primary);
  font-size: 0.8rem;
  font-family: var(--font);
  line-height: 1.4;
  max-width: 360px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5), 0 0 12px rgba(239, 68, 68, 0.15);
  transform: translateX(110%);
  opacity: 0;
  transition: transform 0.35s cubic-bezier(0.22, 1, 0.36, 1), opacity 0.35s ease;
}
.toast.visible {
  transform: translateX(0);
  opacity: 1;
}
.toast.hiding {
  transform: translateX(110%);
  opacity: 0;
}

/* ===== Beaufort Scale Legend ===== */
.beaufort-indicator {
  display: inline-flex;
  align-items: center;
  gap: 0.3rem;
  padding: 0.15rem 0.4rem;
  border-radius: 4px;
  font-size: 0.65rem;
  font-weight: 600;
}
.beaufort-0-3 { background: var(--green-bg); color: var(--green); }
.beaufort-4-5 { background: var(--accent-dim); color: var(--accent); }
.beaufort-6-7 { background: var(--yellow-bg); color: var(--yellow); }
.beaufort-8   { background: var(--red-bg); color: var(--red); }

/* ===== Responsive ===== */
@media (max-width: 768px) {
  #conditions-panel {
    top: auto;
    bottom: 6rem;
    left: 1rem;
    right: 1rem;
    max-width: none;
    min-width: 0;
    display: none;
  }
  #conditions-panel.mobile-visible {
    display: block;
  }
  #compass-panel {
    top: 0.5rem;
    right: 0.5rem;
    width: 200px;
    padding: 0.5rem;
  }
  .compass-rose {
    width: 160px;
    height: 160px;
  }
  #timeline-panel {
    bottom: 0.5rem;
    width: 95vw;
  }
  #info-bar {
    bottom: 4.5rem;
    font-size: 0.65rem;
  }
  #layer-panel {
    bottom: 10rem;
    right: 0.5rem;
    min-width: 130px;
    padding: 0.5rem 0.6rem;
  }
  #action-buttons {
    bottom: 4.5rem;
  }
  #toast-container {
    bottom: 7.5rem;
    right: 0.5rem;
    left: 0.5rem;
    align-items: stretch;
  }
  .toast {
    max-width: none;
  }
  /* Slightly smaller play button on mobile */
  #timeline-play-btn {
    width: 24px;
    height: 24px;
    font-size: 0.6rem;
  }
  /* Compact sea status on mobile */
  .sea-status-label { font-size: 0.75rem; }
  .sea-status-score { font-size: 0.6rem; }
}

/* ===== Leaflet Overrides ===== */
.leaflet-control-attribution {
  background: var(--bg-panel) !important;
  color: var(--text-muted) !important;
  font-size: 0.6rem !important;
}
.leaflet-control-attribution a {
  color: var(--text-secondary) !important;
}
.leaflet-control-zoom a {
  background: var(--bg-panel) !important;
  color: var(--text-primary) !important;
  border-color: var(--border-color) !important;
}
.leaflet-control-zoom a:hover {
  background: var(--bg-panel-hover) !important;
}
