(function() {
  'use strict';

  // ===== Constants =====
  // Default map zoom level — ~7nm viewport for close-in sailing detail
  var DEFAULT_ZOOM = 13;

  // ===== Wind Color Scale =====
  // Color-codes wind speed for visual intensity on arrows:
  // green (<8kn) → cyan (8-15kn) → yellow (15-25kn) → orange (25-33kn) → red (>33kn)
  function windColor(speed, alpha) {
    if (speed < 8)  return 'rgba(34, 197, 94, ' + alpha + ')';   // green — light breeze
    if (speed < 15) return 'rgba(56, 189, 248, ' + alpha + ')';  // cyan — moderate
    if (speed < 25) return 'rgba(234, 179, 8, ' + alpha + ')';   // yellow — fresh
    if (speed < 33) return 'rgba(249, 115, 22, ' + alpha + ')';  // orange — strong
    return 'rgba(239, 68, 68, ' + alpha + ')';                    // red — gale+
  }

  // ===== Wave Color Scale =====
  // Teal gradient based on wave height
  function waveColor(height, alpha) {
    if (height < 0.5) return 'rgba(0, 200, 210, ' + alpha + ')';   // light teal
    if (height < 1.5) return 'rgba(0, 180, 220, ' + alpha + ')';   // teal
    if (height < 3.0) return 'rgba(30, 140, 220, ' + alpha + ')';  // blue-teal
    return 'rgba(80, 100, 240, ' + alpha + ')';                     // deep blue
  }

  // ===== Temperature Color =====
  // Used for map indicator badges
  function tempColor(temp) {
    if (temp < 5)  return '#60a5fa'; // cold — blue
    if (temp < 15) return '#38bdf8'; // cool — light blue
    if (temp < 25) return '#22c55e'; // mild — green
    if (temp < 32) return '#f97316'; // warm — orange
    return '#ef4444';                 // hot — red
  }

  // ===== Pressure Annotation =====
  // Returns H (high) or L (low) based on pressure value
  function pressureAnnotation(hPa) {
    if (hPa >= 1020) return { label: 'H', color: '#38bdf8' };  // high pressure — blue
    if (hPa <= 1005) return { label: 'L', color: '#ef4444' };  // low pressure — red
    return { label: '—', color: '#94a3b8' };                     // normal — gray
  }

  // ===== State =====
  var map, boatMarker, weatherCanvas, weatherCtx;
  var currentWeather = null;
  var directionsData = null;
  var boatPosition = { lat: 41.39, lon: 2.17 }; // Default: Barcelona, Spain
  var boatHeading = 0;
  var currentHourIndex = 0;
  var particles = [];
  var animationFrame = null;

  // Sea status data from API — current + hourly array
  var currentSeaStatus = null;
  var hourlySeaStatuses = null;

  // Leaflet LayerGroup for map indicator badges (temperature, pressure, wind)
  var indicatorLayer = null;

  // Layer visibility toggles — each controls a visualization layer
  var layers = { wind: true, waves: true, precip: true, clouds: true, indicators: true };

  // Cloud cover percentage for the dimming overlay
  var cloudCover = 0;

  // Current wave height — stored for wave color in render loop
  var currentWaveHeight = 0;

  // ===== Playback State =====
  var isPlaying = false;
  var playInterval = null;
  var playIntervalMs = 1500;

  // ===== Boat SVG =====
  var BOAT_SVG = '<svg width="32" height="40" viewBox="0 0 32 40" xmlns="http://www.w3.org/2000/svg">' +
    '<path d="M16 2 L28 34 Q16 40 4 34 Z" fill="#38bdf8" stroke="#0a1628" stroke-width="1.5"/>' +
    '<line x1="16" y1="6" x2="16" y2="30" stroke="#0a1628" stroke-width="1.5"/>' +
    '<path d="M16 8 Q24 16 16 28" fill="rgba(255,255,255,0.3)" stroke="none"/>' +
    '</svg>';

  // ===== Wind direction to compass label =====
  function degToCompass(deg) {
    var dirs = ['N','NNE','NE','ENE','E','ESE','SE','SSE','S','SSW','SW','WSW','W','WNW','NW','NNW'];
    return dirs[Math.round(deg / 22.5) % 16];
  }

  // ===== Beaufort scale from knots =====
  function beaufortClass(kn) {
    if (kn < 11) return 'beaufort-0-3';
    if (kn < 22) return 'beaufort-4-5';
    if (kn < 34) return 'beaufort-6-7';
    return 'beaufort-8';
  }
  function beaufortLabel(kn) {
    if (kn < 1) return 'Calm';
    if (kn < 4) return 'Light air';
    if (kn < 7) return 'Light breeze';
    if (kn < 11) return 'Gentle breeze';
    if (kn < 17) return 'Moderate';
    if (kn < 22) return 'Fresh';
    if (kn < 28) return 'Strong';
    if (kn < 34) return 'Near gale';
    if (kn < 41) return 'Gale';
    if (kn < 48) return 'Strong gale';
    return 'Storm';
  }

  // ===== Toast Notification Helper =====
  function showToast(message) {
    var container = document.getElementById('toast-container');
    if (!container) return;

    var toast = document.createElement('div');
    toast.className = 'toast';
    toast.textContent = message;
    container.appendChild(toast);

    requestAnimationFrame(function() {
      toast.classList.add('visible');
    });

    setTimeout(function() {
      toast.classList.remove('visible');
      toast.classList.add('hiding');
      setTimeout(function() {
        if (toast.parentNode) toast.parentNode.removeChild(toast);
      }, 400);
    }, 5000);
  }

  // ===== Initialize Map =====
  function initMap() {
    map = L.map('map', {
      center: [boatPosition.lat, boatPosition.lon],
      zoom: DEFAULT_ZOOM,
      zoomControl: true,
      attributionControl: true
    });

    // Dark nautical-style tiles
    L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
      attribution: '&copy; <a href="https://carto.com/">CARTO</a> | Weather: <a href="https://open-meteo.com/">Open-Meteo</a>',
      subdomains: 'abcd',
      maxZoom: 19
    }).addTo(map);

    // Create boat marker
    var boatIcon = L.divIcon({
      className: 'boat-marker',
      html: BOAT_SVG,
      iconSize: [32, 40],
      iconAnchor: [16, 20]
    });
    boatMarker = L.marker([boatPosition.lat, boatPosition.lon], { icon: boatIcon, draggable: true }).addTo(map);

    // Allow dragging the boat to change position
    boatMarker.on('dragend', function(e) {
      var pos = e.target.getLatLng();
      boatPosition = { lat: pos.lat, lon: pos.lng };
      updateInfoBar();
      refreshData();
    });

    // Click map to move boat
    map.on('click', function(e) {
      boatPosition = { lat: e.latlng.lat, lon: e.latlng.lng };
      boatMarker.setLatLng(e.latlng);
      updateInfoBar();
      refreshData();
    });

    // Initialize the indicator layer group
    indicatorLayer = L.layerGroup().addTo(map);

    // Setup weather animation canvas
    weatherCanvas = document.getElementById('weather-canvas');
    weatherCtx = weatherCanvas.getContext('2d');
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
  }

  function resizeCanvas() {
    weatherCanvas.width = window.innerWidth;
    weatherCanvas.height = window.innerHeight;
  }

  // ===== Weather Particle Animation =====
  // Creates particles for wind, waves, and precipitation based on current weather data.
  function initParticles(weather) {
    particles = [];
    if (!weather) return;

    var hourData = weather.hourly[currentHourIndex] || weather.current;
    var windSpeed = hourData.windSpeed || 0;
    var windDir = hourData.windDirection || 0;
    var precip = hourData.precipitation || 0;
    var temperature = hourData.temperature || 0;

    // Store cloud cover for the dimming overlay
    cloudCover = hourData.cloudCover || 0;

    // --- Wind particles — arrows that show direction & intensity ---
    // Count scales with wind speed; each carries its speed for color lookup
    var windCount = Math.min(Math.floor(windSpeed * 3), 150);
    var windRad = (windDir + 90) * Math.PI / 180;
    for (var i = 0; i < windCount; i++) {
      particles.push({
        type: 'wind',
        x: Math.random() * weatherCanvas.width,
        y: Math.random() * weatherCanvas.height,
        speed: (windSpeed * 0.3 + Math.random() * 2),
        angle: windRad + (Math.random() - 0.5) * 0.3,
        life: Math.random() * 200 + 100,
        maxLife: 300,
        size: 1.5 + Math.random() * 2,
        windSpeed: windSpeed  // stored for color-coding in render
      });
    }

    // --- Wave particles — sinusoidal curves clustered near the boat ---
    // Position within a radius of the boat's screen coordinates so they
    // appear over water (since the boat is on water), not over land
    if (hourData.waveHeight !== null && hourData.waveHeight > 0) {
      currentWaveHeight = hourData.waveHeight;
      var waveDir = hourData.waveDirection !== null ? hourData.waveDirection : windDir;
      var waveRad = (waveDir + 90) * Math.PI / 180;
      // Fewer, cleaner wave curves than the old semi-circles
      var waveCount = Math.min(Math.floor((hourData.wavePeriod || 5) * 3), 45);

      // Get boat position on screen for clustering
      var boatPoint = map.latLngToContainerPoint([boatPosition.lat, boatPosition.lon]);
      var spreadRadius = Math.min(weatherCanvas.width, weatherCanvas.height) * 0.45;

      for (var w = 0; w < waveCount; w++) {
        // Spread around the boat with Gaussian-like distribution (sum of randoms)
        var angle = Math.random() * Math.PI * 2;
        var dist = (Math.random() + Math.random()) * 0.5 * spreadRadius;
        var wx = boatPoint.x + Math.cos(angle) * dist;
        var wy = boatPoint.y + Math.sin(angle) * dist;

        particles.push({
          type: 'wave',
          x: wx,
          y: wy,
          speed: 0.3 + Math.random() * 0.5,
          angle: waveRad + (Math.random() - 0.5) * 0.4,
          life: Math.random() * 300 + 150,
          maxLife: 450,
          size: 6 + hourData.waveHeight * 3 + Math.random() * 4,
          // Sinusoidal wave properties
          waveLen: 12 + Math.random() * 8,       // wavelength of the sine
          waveAmp: 2 + hourData.waveHeight * 1.5, // amplitude
          wavePhase: Math.random() * Math.PI * 2,  // phase offset
          wavePeriods: 2 + Math.floor(Math.random() * 2) // 2-3 periods
        });
      }
    }

    // --- Precipitation: snow when cold (< 2°C), rain otherwise ---
    if (precip > 0) {
      if (temperature < 2) {
        var snowCount = Math.min(Math.floor(precip * 40), 250);
        for (var s = 0; s < snowCount; s++) {
          particles.push({
            type: 'snow',
            x: Math.random() * weatherCanvas.width,
            y: Math.random() * weatherCanvas.height,
            speed: 0.5 + Math.random() * 1.5,
            angle: Math.PI / 2 + (Math.random() - 0.5) * 0.3,
            life: Math.random() * 200 + 100,
            maxLife: 300,
            size: 1.5 + Math.random() * 2.5,
            wobble: Math.random() * Math.PI * 2,
            wobbleSpeed: 0.02 + Math.random() * 0.03
          });
        }
      } else {
        var rainCount = Math.min(Math.floor(precip * 40), 250);
        for (var r = 0; r < rainCount; r++) {
          particles.push({
            type: 'rain',
            x: Math.random() * weatherCanvas.width,
            y: Math.random() * weatherCanvas.height,
            speed: 4 + Math.random() * 4 + precip,
            angle: Math.PI / 2 + (windRad - Math.PI) * 0.15,
            life: Math.random() * 60 + 20,
            maxLife: 80,
            size: 1 + Math.random()
          });
        }
      }
    }
  }

  // ===== Draw Arrow =====
  // Renders a single wind arrow with shaft + V-shaped arrowhead at the tip
  function drawArrow(ctx, x, y, angle, length, headSize, color, lineWidth) {
    var tailX = x - Math.cos(angle) * length;
    var tailY = y - Math.sin(angle) * length;

    // Shaft line
    ctx.beginPath();
    ctx.moveTo(tailX, tailY);
    ctx.lineTo(x, y);
    ctx.strokeStyle = color;
    ctx.lineWidth = lineWidth;
    ctx.stroke();

    // V-shaped arrowhead at tip
    var headAngle = 0.45; // ~25 degrees spread
    var hx1 = x - Math.cos(angle - headAngle) * headSize;
    var hy1 = y - Math.sin(angle - headAngle) * headSize;
    var hx2 = x - Math.cos(angle + headAngle) * headSize;
    var hy2 = y - Math.sin(angle + headAngle) * headSize;

    ctx.beginPath();
    ctx.moveTo(hx1, hy1);
    ctx.lineTo(x, y);
    ctx.lineTo(hx2, hy2);
    ctx.strokeStyle = color;
    ctx.lineWidth = lineWidth + 0.3;
    ctx.stroke();
  }

  // ===== Draw Sinusoidal Wave =====
  // Renders a wavy curve (∿) using quadratic bezier segments
  function drawWave(ctx, x, y, angle, size, amp, waveLen, periods, color, lineWidth) {
    ctx.beginPath();

    // Total length of the wave curve
    var totalLen = waveLen * periods;
    // Perpendicular direction for the wave oscillation
    var perpAngle = angle + Math.PI / 2;

    // Start point
    var startX = x - Math.cos(angle) * totalLen * 0.5;
    var startY = y - Math.sin(angle) * totalLen * 0.5;
    ctx.moveTo(startX, startY);

    // Draw smooth wave using quadratic curves — one curve per half-period
    var segments = periods * 2;
    var segLen = totalLen / segments;

    for (var i = 0; i < segments; i++) {
      // Direction alternates above/below the travel axis
      var dir = (i % 2 === 0) ? 1 : -1;

      // Control point (midpoint of segment, offset perpendicular)
      var midX = startX + Math.cos(angle) * segLen * (i + 0.5);
      var midY = startY + Math.sin(angle) * segLen * (i + 0.5);
      var cpX = midX + Math.cos(perpAngle) * amp * dir;
      var cpY = midY + Math.sin(perpAngle) * amp * dir;

      // End point of this segment
      var endX = startX + Math.cos(angle) * segLen * (i + 1);
      var endY = startY + Math.sin(angle) * segLen * (i + 1);

      ctx.quadraticCurveTo(cpX, cpY, endX, endY);
    }

    ctx.strokeStyle = color;
    ctx.lineWidth = lineWidth;
    ctx.lineCap = 'round';
    ctx.stroke();
  }

  // Main animation loop — renders all particle types and the cloud dimming overlay
  function animateParticles() {
    weatherCtx.clearRect(0, 0, weatherCanvas.width, weatherCanvas.height);

    // Cloud cover dimming overlay
    if (layers.clouds && cloudCover > 0) {
      var dimAlpha = Math.min(cloudCover / 100 * 0.18, 0.18);
      weatherCtx.fillStyle = 'rgba(10, 20, 35, ' + dimAlpha + ')';
      weatherCtx.fillRect(0, 0, weatherCanvas.width, weatherCanvas.height);
    }

    for (var i = particles.length - 1; i >= 0; i--) {
      var p = particles[i];

      p.x += Math.cos(p.angle) * p.speed;
      p.y += Math.sin(p.angle) * p.speed;
      p.life--;

      // Snow lateral wobble
      if (p.type === 'snow') {
        p.wobble += p.wobbleSpeed;
        p.x += Math.sin(p.wobble) * 0.5;
      }

      // Wrap around screen edges
      if (p.x < -20) p.x = weatherCanvas.width + 20;
      if (p.x > weatherCanvas.width + 20) p.x = -20;
      if (p.y < -20) p.y = weatherCanvas.height + 20;
      if (p.y > weatherCanvas.height + 20) p.y = -20;

      // Fade in/out based on remaining life
      var alpha = Math.min(p.life / 30, 1) * 0.6;

      // --- Render each particle type, skip if layer is disabled ---

      if (p.type === 'wind' && layers.wind) {
        // Wind: colored arrow with arrowhead, length proportional to size
        var arrowLen = p.size * 8;
        var headSize = p.size * 2.5;
        var color = windColor(p.windSpeed, alpha);
        drawArrow(weatherCtx, p.x, p.y, p.angle, arrowLen, headSize, color, p.size * 0.5);

      } else if (p.type === 'wave' && layers.waves) {
        // Waves: sinusoidal curve (∿ shape) in teal gradient
        var wAlpha = alpha * 0.5;
        var wColor = waveColor(currentWaveHeight, wAlpha);
        drawWave(
          weatherCtx, p.x, p.y, p.angle,
          p.size, p.waveAmp, p.waveLen, p.wavePeriods,
          wColor, 1.5
        );

      } else if (p.type === 'rain' && layers.precip) {
        // Rain: angled streak lines
        var rtX = p.x - Math.cos(p.angle) * 6;
        var rtY = p.y - Math.sin(p.angle) * 6;
        weatherCtx.beginPath();
        weatherCtx.moveTo(rtX, rtY);
        weatherCtx.lineTo(p.x, p.y);
        weatherCtx.strokeStyle = 'rgba(100, 160, 255, ' + (alpha * 0.7) + ')';
        weatherCtx.lineWidth = p.size;
        weatherCtx.stroke();

      } else if (p.type === 'snow' && layers.precip) {
        // Snow: soft circular dots
        weatherCtx.beginPath();
        weatherCtx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        weatherCtx.fillStyle = 'rgba(220, 235, 255, ' + (alpha * 0.7) + ')';
        weatherCtx.fill();
      }

      // Respawn dead particles — reset position based on type
      if (p.life <= 0) {
        if (p.type === 'wave') {
          // Respawn waves near the boat to keep them over water
          var boatPt = map.latLngToContainerPoint([boatPosition.lat, boatPosition.lon]);
          var spread = Math.min(weatherCanvas.width, weatherCanvas.height) * 0.45;
          var rAngle = Math.random() * Math.PI * 2;
          var rDist = (Math.random() + Math.random()) * 0.5 * spread;
          p.x = boatPt.x + Math.cos(rAngle) * rDist;
          p.y = boatPt.y + Math.sin(rAngle) * rDist;
        } else {
          p.x = Math.random() * weatherCanvas.width;
          p.y = Math.random() * weatherCanvas.height;
        }
        p.life = p.maxLife;
        if (p.type === 'snow') {
          p.wobble = Math.random() * Math.PI * 2;
        }
      }
    }

    animationFrame = requestAnimationFrame(animateParticles);
  }

  // ===== Update Map Indicators =====
  // Places Leaflet divIcon markers on the map for temperature, pressure, and wind.
  // These badges stay anchored to geographic coordinates and move with panning/zooming.
  function updateMapIndicators(weather, hourIndex) {
    if (!indicatorLayer || !map) return;

    // Clear existing indicators
    indicatorLayer.clearLayers();

    // Hide if layer is toggled off
    if (!layers.indicators) return;

    if (!weather) return;
    var data = weather.hourly[hourIndex] || weather.current;
    if (!data) return;

    var lat = boatPosition.lat;
    var lon = boatPosition.lon;

    // Calculate offsets in degrees — roughly 0.003° ≈ 300m at mid latitudes
    // This spaces the badges around the boat so they don't overlap
    var offset = 0.003;

    // --- Temperature badge ---
    var tColor = tempColor(data.temperature);
    var tempIcon = L.divIcon({
      className: 'map-indicator-container',
      html: '<div class="map-indicator temp-indicator" style="background:' + tColor + '22; border-color:' + tColor + '; color:' + tColor + '">' +
            '<span class="indicator-icon">🌡</span>' +
            '<span class="indicator-value">' + data.temperature.toFixed(1) + '°</span>' +
            '</div>',
      iconSize: [80, 30],
      iconAnchor: [40, 15]
    });
    L.marker([lat + offset * 1.5, lon - offset * 2], { icon: tempIcon, interactive: false }).addTo(indicatorLayer);

    // --- Pressure badge with H/L annotation ---
    var pInfo = pressureAnnotation(data.pressure);
    var pressureIcon = L.divIcon({
      className: 'map-indicator-container',
      html: '<div class="map-indicator pressure-indicator" style="background:' + pInfo.color + '22; border-color:' + pInfo.color + '; color:' + pInfo.color + '">' +
            '<span class="indicator-label">' + pInfo.label + '</span>' +
            '<span class="indicator-value">' + Math.round(data.pressure) + '</span>' +
            '<span class="indicator-unit">hPa</span>' +
            '</div>',
      iconSize: [90, 30],
      iconAnchor: [45, 15]
    });
    L.marker([lat + offset * 1.5, lon + offset * 2], { icon: pressureIcon, interactive: false }).addTo(indicatorLayer);

    // --- Wind speed + direction badge ---
    var wColor = windColor(data.windSpeed, 1);
    var windDir = data.windDirection || 0;
    var compassLabel = degToCompass(windDir);
    var windBadgeIcon = L.divIcon({
      className: 'map-indicator-container',
      html: '<div class="map-indicator wind-indicator" style="background:rgba(56, 189, 248, 0.12); border-color:' + wColor + '; color:' + wColor + '">' +
            '<span class="indicator-arrow" style="transform: rotate(' + windDir + 'deg)">↓</span>' +
            '<span class="indicator-value">' + data.windSpeed.toFixed(0) + 'kn</span>' +
            '<span class="indicator-dir">' + compassLabel + '</span>' +
            '</div>',
      iconSize: [100, 30],
      iconAnchor: [50, 15]
    });
    L.marker([lat - offset * 2, lon], { icon: windBadgeIcon, interactive: false }).addTo(indicatorLayer);

    // --- Wave badge (only when wave data available) ---
    if (data.waveHeight !== null && data.waveHeight > 0) {
      var waveBadgeColor = waveColor(data.waveHeight, 1);
      var waveBadgeIcon = L.divIcon({
        className: 'map-indicator-container',
        html: '<div class="map-indicator wave-badge-indicator" style="background:rgba(0, 200, 210, 0.12); border-color:' + waveBadgeColor + '; color:' + waveBadgeColor + '">' +
              '<span class="indicator-icon">🌊</span>' +
              '<span class="indicator-value">' + data.waveHeight.toFixed(1) + 'm</span>' +
              '</div>',
        iconSize: [80, 30],
        iconAnchor: [40, 15]
      });
      L.marker([lat - offset * 2, lon + offset * 3], { icon: waveBadgeIcon, interactive: false }).addTo(indicatorLayer);
    }
  }

  // ===== Update Sea Status Indicator =====
  function updateSeaStatus(hourIndex) {
    var el = document.getElementById('sea-status');
    if (!el) return;

    var status = null;
    if (hourlySeaStatuses && typeof hourIndex === 'number' && hourlySeaStatuses[hourIndex]) {
      status = hourlySeaStatuses[hourIndex];
    } else if (currentSeaStatus) {
      status = currentSeaStatus;
    }

    if (!status) {
      el.innerHTML = '';
      el.className = '';
      return;
    }

    var wasExpanded = el.classList.contains('expanded');
    el.className = 'level-' + status.level + (wasExpanded ? ' expanded' : '');

    var reasonsHtml = '';
    if (status.reasons && status.reasons.length > 0) {
      reasonsHtml = '<div class="sea-status-reasons">';
      for (var i = 0; i < status.reasons.length; i++) {
        reasonsHtml += '<div class="sea-status-reason">' + status.reasons[i] + '</div>';
      }
      reasonsHtml += '</div>';
    }

    el.innerHTML =
      '<div class="sea-status-main">' +
        '<div class="sea-status-dot"></div>' +
        '<span class="sea-status-label">' + status.label + '</span>' +
        '<span class="sea-status-score">' + status.score + '</span>' +
        '<span class="sea-status-chevron">▼</span>' +
      '</div>' +
      reasonsHtml;

    el.onclick = function() {
      el.classList.toggle('expanded');
    };
  }

  // ===== Update Conditions Panel =====
  function updateConditionsPanel(weather) {
    if (!weather) return;
    var data = weather.hourly[currentHourIndex] || weather.current;
    var panel = document.getElementById('conditions-panel');
    if (!panel) return;

    var windDir = data.windDirection || 0;
    var windCompass = degToCompass(windDir);
    var bClass = beaufortClass(data.windSpeed);
    var bLabel = beaufortLabel(data.windSpeed);

    var timeStr = data.time ? new Date(data.time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : 'Now';

    var wavesHtml = '';
    if (data.waveHeight !== null) {
      var waveDir = data.waveDirection !== null ? ' ' + degToCompass(data.waveDirection) : '';
      wavesHtml = '<div class="condition-row">' +
        '<span class="condition-label">Waves</span>' +
        '<span class="condition-value">' + data.waveHeight.toFixed(1) + '<span class="condition-unit">m</span>' + waveDir + '</span>' +
        '</div>';
    }

    var wavePeriodHtml = '';
    if (data.wavePeriod !== null) {
      wavePeriodHtml = '<div class="condition-row">' +
        '<span class="condition-label">Wave period</span>' +
        '<span class="condition-value">' + data.wavePeriod.toFixed(1) + '<span class="condition-unit">s</span></span>' +
        '</div>';
    }

    var conditionsHtml =
      '<div class="conditions-header">' +
        '<h2>Current Conditions</h2>' +
        '<span class="update-time">' + timeStr + '</span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Wind</span>' +
        '<span class="condition-value">' +
          '<span class="wind-arrow" style="transform: rotate(' + windDir + 'deg)">↓</span>' +
          data.windSpeed.toFixed(1) + '<span class="condition-unit">kn</span> ' + windCompass +
        '</span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Gusts</span>' +
        '<span class="condition-value">' + data.windGusts.toFixed(1) + '<span class="condition-unit">kn</span></span>' +
      '</div>' +
      '<div class="condition-row">' +
        '<span class="condition-label">Beaufort</span>' +
        '<span class="condition-value"><span class="beaufort-indicator ' + bClass + '">' + bLabel + '</span></span>' +
