  // ===== Update Compass Rose =====
  function updateCompassRose(directions, hourIndex) {
    if (!directions) return;
    var panel = document.getElementById('compass-panel');
    if (!panel) return;

    var roseHtml = '<div class="compass-title">Direction Analysis</div><div class="compass-rose">';
    roseHtml += '<div class="compass-center">⚓</div>';

    directions.directions.forEach(function(dir) {
      var score = dir.score;
      var rating = dir.rating;
      var summary = dir.summary;
      if (dir.hourly && typeof hourIndex === 'number' && dir.hourly[hourIndex]) {
        score = dir.hourly[hourIndex].score;
        rating = dir.hourly[hourIndex].rating;
        summary = dir.hourly[hourIndex].summary;
      }

      roseHtml +=
        '<div class="compass-direction dir-' + dir.name + '" data-summary="' + summary + '" data-rating="' + rating + '">' +
          '<span class="dir-label" style="color: var(--' + rating + ')">' + dir.name + '</span>' +
          '<div class="dir-segment ' + rating + '"></div>' +
          '<span class="dir-score">' + score + '</span>' +
        '</div>';
    });

    roseHtml += '</div>';
    roseHtml += '<div id="compass-tooltip" class="compass-tooltip"></div>';
    panel.innerHTML = roseHtml;

    panel.querySelectorAll('.compass-direction').forEach(function(el) {
      el.addEventListener('mouseenter', function() {
        var tip = document.getElementById('compass-tooltip');
        if (tip) {
          tip.textContent = el.dataset.summary;
          tip.classList.add('visible');
        }
      });
      el.addEventListener('mouseleave', function() {
        var tip = document.getElementById('compass-tooltip');
        if (tip) tip.classList.remove('visible');
      });
    });
  }

  // ===== Update Timeline =====
  function updateTimeline(weather) {
    if (!weather || !weather.hourly || weather.hourly.length === 0) return;
    var slider = document.getElementById('timeline-slider');
    var timeDisplay = document.getElementById('timeline-time');
    var ticksContainer = document.getElementById('timeline-ticks');
    if (!slider) return;

    slider.max = weather.hourly.length - 1;
    slider.value = currentHourIndex;

    var hourData = weather.hourly[currentHourIndex];
    if (hourData && timeDisplay) {
      var dt = new Date(hourData.time);
      timeDisplay.textContent = dt.toLocaleString([], {
        weekday: 'short', month: 'short', day: 'numeric',
        hour: '2-digit', minute: '2-digit'
