            if (this.checked) {
              updateMapIndicators(currentWeather, currentHourIndex);
            } else {
              if (indicatorLayer) indicatorLayer.clearLayers();
            }
          }
        }
      });
    });
  }

  // ===== Geolocation (silent attempt on load) =====
  function tryGeolocation() {
