// Verify the template includes the new Indicators layer toggle checkbox
async function testIndicatorsLayerToggle() {
  const html = templates.get('sailing-app');
  assert(html, 'Template sailing-app should exist');

  // Check that the indicators layer toggle is present
  assert(html.includes('data-layer="indicators"'), 'Template should have indicators layer toggle');
  assert(html.includes('id="layer-indicators"'), 'Template should have layer-indicators checkbox ID');
  assert(html.includes('Indicators'), 'Template should have Indicators label text');

  // Verify all original layers are still present
  assert(html.includes('data-layer="wind"'), 'Wind layer toggle should exist');
  assert(html.includes('data-layer="waves"'), 'Waves layer toggle should exist');
  assert(html.includes('data-layer="precip"'), 'Precip layer toggle should exist');
  assert(html.includes('data-layer="clouds"'), 'Clouds layer toggle should exist');
}
