// Get the JS source to understand boat dragging and tile layers
const resp = await fetch('http://localhost:3001/_assets/sailing-weather.js');
const js = await resp.text();

// Extract relevant sections
const lines = js.split('\n');
const sections = [];

// Find boat/marker related code
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  if (line.includes('boatMarker') || line.includes('dragend') || line.includes('drag') || 
      line.includes('tileLayer') || line.includes('tile') || line.includes('fetchWeather') ||
      line.includes('setPosition') || line.includes('updateBoat') || line.includes('L.marker') ||
      line.includes('initMap') || line.includes('const map') || line.includes('baseLayer')) {
    const start = Math.max(0, i - 2);
    const end = Math.min(lines.length, i + 5);
