/* ===== Reset & Base ===== */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg-dark: #0a1628;
  --bg-panel: rgba(10, 22, 40, 0.88);
  --bg-panel-hover: rgba(15, 30, 55, 0.92);
  --border-color: rgba(100, 160, 220, 0.25);
  --text-primary: #e2e8f0;
  --text-secondary: #94a3b8;
  --text-muted: #64748b;
  --accent: #38bdf8;
  --accent-dim: rgba(56, 189, 248, 0.15);
  --green: #22c55e;
  --yellow: #eab308;
  --red: #ef4444;
  --black: #64748b;
  --green-bg: rgba(34, 197, 94, 0.15);
  --yellow-bg: rgba(234, 179, 8, 0.15);
  --red-bg: rgba(239, 68, 68, 0.15);
  --black-bg: rgba(100, 116, 139, 0.2);
  --font: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', monospace;
}

html, body {
  height: 100%; width: 100%;
  font-family: var(--font);
  background: var(--bg-dark);
  color: var(--text-primary);
  overflow: hidden;
}

/* ===== Map Container ===== */
#map {
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  z-index: 1;
}

/* ===== Weather Animation Canvas ===== */
#weather-canvas {
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  z-index: 2;
  pointer-events: none;
}

/* ===== Loading Overlay ===== */
#loading-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  z-index: 1000;
  background: var(--bg-dark);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 1.5rem;
  transition: opacity 0.5s ease;
}
#loading-overlay.hidden {
  opacity: 0;
  pointer-events: none;
}
#loading-overlay .spinner {
  width: 48px; height: 48px;
  border: 3px solid var(--border-color);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}
#loading-overlay .loading-text {
  color: var(--text-secondary);
  font-size: 0.9rem;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ===== Panels ===== */
.panel {
  position: absolute;
  z-index: 10;
  background: var(--bg-panel);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid var(--border-color);
  border-radius: 12px;
  padding: 1rem;
  color: var(--text-primary);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
  transition: transform 0.3s ease, opacity 0.3s ease;
}

/* ===== Conditions Panel (top-left) ===== */
#conditions-panel {
  top: 1rem;
  left: 1rem;
  min-width: 260px;
  max-width: 320px;
}
.conditions-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 0.75rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--border-color);
}
.conditions-header h2 {
  font-size: 0.85rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-secondary);
}
.conditions-header .update-time {
  font-size: 0.7rem;
  color: var(--text-muted);
}
.condition-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.35rem 0;
}
.condition-label {
  font-size: 0.8rem;
  color: var(--text-secondary);
}
.condition-value {
  font-size: 0.9rem;
  font-weight: 600;
  font-family: var(--font-mono);
  color: var(--text-primary);
}
.condition-unit {
  font-size: 0.7rem;
  color: var(--text-muted);
  margin-left: 0.25rem;
  font-weight: 400;
}
.wind-arrow {
  display: inline-block;
  margin-right: 0.35rem;
  transition: transform 0.3s ease;
  color: var(--accent);
}

/* ===== Sea Status Indicator ===== */
#sea-status {
  margin-bottom: 0.75rem;
  padding: 0.65rem 0.75rem;
  border-radius: 8px;
  transition: background 0.4s ease, box-shadow 0.4s ease;
  cursor: pointer;
}
#sea-status.level-green {
  background: var(--green-bg);
  border-left: 3px solid var(--green);
  box-shadow: 0 0 12px rgba(34, 197, 94, 0.15);
}
#sea-status.level-yellow {
  background: var(--yellow-bg);
