/* When the boat is moved from land to nearest water, the marker
   gets a brief glow/pulse to indicate repositioning */

@keyframes boat-snap-glow {
  0% {
    filter: drop-shadow(0 0 4px rgba(56, 189, 248, 0.5));
    transform: scale(1);
  }
  30% {
    filter: drop-shadow(0 0 20px rgba(56, 189, 248, 1)) drop-shadow(0 0 40px rgba(56, 189, 248, 0.5));
    transform: scale(1.25);
  }
  60% {
    filter: drop-shadow(0 0 12px rgba(34, 197, 94, 0.8)) drop-shadow(0 0 24px rgba(34, 197, 94, 0.3));
    transform: scale(1.1);
  }
  100% {
    filter: drop-shadow(0 0 4px rgba(0, 0, 0, 0.5));
    transform: scale(1);
  }
}

.boat-marker.boat-snap-pulse {
  animation: boat-snap-glow 1.5s ease-out forwards;
}

/* Override the toast border color for water-detection toasts (anchor icon) */
.toast {
  transition: transform 0.35s cubic-bezier(0.22, 1, 0.36, 1), opacity 0.35s ease,
              border-color 0.3s ease;
}
