<body>

  <!-- Loading overlay — shown until first data fetch completes -->
  <div id="loading-overlay">
    <div class="spinner"></div>
    <div class="loading-text">Fetching weather data…</div>
  </div>

  <!-- Map fills the entire viewport -->
  <div id="map"></div>

  <!-- Canvas overlay for wind/wave/rain/snow particle animations -->
  <canvas id="weather-canvas"></canvas>

  <!-- Current Conditions Panel (top-left) -->
  <div id="conditions-panel" class="panel">
    <!-- Sea Status Indicator — populated by JS from weather API response -->
    <div id="sea-status"></div>

    <div class="conditions-header">
      <h2>Current Conditions</h2>
      <span class="update-time">Loading…</span>
    </div>
    <div class="condition-row">
      <span class="condition-label">Waiting for data</span>
      <span class="condition-value">—</span>
    </div>
  </div>

  <!-- Compass Rose Panel (top-right) -->
  <div id="compass-panel" class="panel">
    <div class="compass-title">Direction Analysis</div>
    <div class="compass-rose">
      <div class="compass-center">⚓</div>
    </div>
  </div>

  <!-- Boat Info Bar (bottom-left) -->
  <div id="info-bar">
    <div class="info-item">
      <span class="info-label">LAT</span>
      <span class="info-value" id="info-lat">—</span>
    </div>
    <div class="info-item">
      <span class="info-label">LON</span>
      <span class="info-value" id="info-lon">—</span>
    </div>
  </div>

  <!-- Layer Toggle Panel (bottom-right, above action buttons) -->
  <div id="layer-panel" class="panel">
    <div class="layer-panel-title">Layers</div>
    <div class="layer-row">
      <input type="checkbox" id="layer-wind" class="layer-toggle" data-layer="wind" checked>
      <label for="layer-wind">Wind</label>
    </div>
    <div class="layer-row">
      <input type="checkbox" id="layer-waves" class="layer-toggle" data-layer="waves" checked>
      <label for="layer-waves">Waves</label>
    </div>
    <div class="layer-row">
      <input type="checkbox" id="layer-precip" class="layer-toggle" data-layer="precip" checked>
      <label for="layer-precip">Precipitation</label>
    </div>
    <div class="layer-row">
      <input type="checkbox" id="layer-clouds" class="layer-toggle" data-layer="clouds" checked>
      <label for="layer-clouds">Clouds</label>
    </div>
    <div class="layer-row">
      <input type="checkbox" id="layer-indicators" class="layer-toggle" data-layer="indicators" checked>
      <label for="layer-indicators">Indicators</label>
    </div>
  </div>

  <!-- Action Buttons (bottom-right) -->
  <div id="action-buttons">
    <button id="location-btn" type="button" aria-label="Get my location"
      title="Use your device GPS to center the map on your current position">
      <span class="location-icon">📍</span>
      My Location
    </button>
    <button id="refresh-btn" type="button" aria-label="Refresh weather data">
      <span class="refresh-icon">⟳</span>
      Refresh
    </button>
  </div>

  <!-- Timeline Panel (bottom-center) -->
  <div id="timeline-panel" class="panel">
    <div class="timeline-header">
      <span class="timeline-label">Forecast Timeline</span>
      <button id="timeline-play-btn" type="button"
        aria-label="Play forecast animation"
        title="Auto-advance through forecast hours"
        data-play-interval="{{PLAY_INTERVAL_MS}}">▶</button>
      <span class="timeline-time" id="timeline-time">—</span>
    </div>
    <input type="range" class="timeline-slider" id="timeline-slider"
      min="0" max="47" value="0" aria-label="Forecast hour selector">
    <div class="timeline-ticks" id="timeline-ticks"></div>
  </div>

  <!-- Toast notification container — used for location errors and other alerts -->
  <div id="toast-container"></div>

  <!-- Leaflet JS -->
  <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"
    integrity="sha256-20nQCchB9co0qIjJZRGuk2/Z9VM+kNiyxNV1lvTlZBo=" crossorigin=""></script>

  <!-- App JS (served from DB with water detection utilities) -->
  <script src="/api/sailing-js"></script>
</body>
