// Serve the modified sailing weather JS from the database
// The JS includes water detection utilities for land/water snapping
async function serveSailingJs(c: any) {
  const rows = await db.query("SELECT content FROM _temp_build WHERE id = 1");
  if (rows.length === 0) {
    return c.text("// Asset not found", 404);
  }

  // Set JavaScript MIME type and no-cache for development
  c.header("Content-Type", "application/javascript; charset=utf-8");
  c.header("Cache-Control", "no-cache");
  return c.body(rows[0].content);
}
